  1	import * as React from 'react';
  2	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  3	import { CommonModalProps } from '@odf/shared/modals';
  4	import { SecretModel } from '@odf/shared/models';
  5	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  6	import { k8sGet } from '@openshift-console/dynamic-plugin-sdk';
  7	import {
  8	  Modal,
  9	  ModalVariant,
 10	  Button,
 11	  ButtonVariant,
 12	  Alert,
 13	  AlertVariant,
 14	  Label,
 15	} from '@patternfly/react-core';
 16	import { UserIcon } from '@patternfly/react-icons';
 17	import { getProviderLabel } from '../../../utils';
 18	import { StorageType, SecretRef, ClientType } from '../types';
 19	import { hasOBCOwnerRef } from '../utils';
 20	import { LoginFormProps, LoginBody } from './LoginForm';
 21	
 22	const LoginModal: React.FC<CommonModalProps<LoginFormProps>> = ({
 23	  closeModal,
 24	  isOpen,
 25	  extraProps: { onLogin, logout, providerType, type = ClientType.S3 },
 26	}) => {
 27	  const { t } = useCustomTranslation();
 28	
 29	  const [secretRef, setSecretRef] = React.useState<SecretRef>({
 30	    name: '',
 31	    namespace: '',
 32	  });
 33	  const [storageType, setStorageType] = React.useState<StorageType>(
 34	    StorageType.Session
 35	  );
 36	  const [isLoading, setIsLoading] = React.useState(false);
 37	  const [error, setError] = React.useState<string | null>(null);
 38	
 39	  const storeCredentials = async () => {
 40	    if (!secretRef.name || !secretRef.namespace) {
 41	      return;
 42	    }
 43	
 44	    setIsLoading(true);
 45	    setError(null);
 46	
 47	    try {
 48	      const secret = await k8sGet({
 49	        model: SecretModel,
 50	        name: secretRef.name,
 51	        ns: secretRef.namespace,
 52	      });
 53	
 54	      const obcOwnerRef = hasOBCOwnerRef(secret);
 55	
 56	      // Block login from IAM tab if Secret has OBC owner reference
 57	      if (obcOwnerRef && type === ClientType.IAM) {
 58	        setError(
 59	          t(
 60	            'IAM is not supported for ObjectBucketClaim accounts. Please select a different Secret.'
 61	          )
 62	        );
 63	        setIsLoading(false);
 64	        return;
 65	      }
 66	
 67	      logout();
 68	      onLogin(secretRef, storageType, obcOwnerRef);
 69	      closeModal();
 70	    } catch (err) {
 71	      setError(
 72	        err?.message ||
 73	          t(
 74	            'Failed to fetch Secret. Please check the Secret name and namespace.'
 75	          )
 76	      );
 77	    } finally {
 78	      setIsLoading(false);
 79	    }
 80	  };
 81	
 82	  return (
 83	    <Modal
 84	      title={t('Sign in to another account')}
 85	      titleIconVariant={UserIcon}
 86	      isOpen={isOpen}
 87	      onClose={closeModal}
 88	      description={t('Log in to another account to access linked buckets.')}
 89	      variant={ModalVariant.medium}
 90	      actions={[
 91	        <ButtonBar inProgress={isLoading} errorMessage={null}>
 92	          <span>
 93	            <Button
 94	              variant={ButtonVariant.primary}
 95	              onClick={storeCredentials}
 96	              isDisabled={!secretRef.name || !secretRef.namespace || isLoading}
 97	              className="pf-v6-u-mr-xs"
 98	            >
 99	              {t('Sign in')}
100	            </Button>
101	            <Button
102	              variant={ButtonVariant.link}
103	              onClick={closeModal}
104	              className="pf-v6-u-ml-xs"
105	            >
106	              {t('Cancel')}
107	            </Button>
108	          </span>
109	        </ButtonBar>,
110	      ]}
111	    >
112	      <Alert
113	        variant={AlertVariant.warning}
114	        title={t('You will be signed out of your current account.')}
115	      >
116	        {t('To return, sign in again with your account credentials.')}
117	      </Alert>
118	      {error && (
119	        <Alert
120	          variant={AlertVariant.danger}
121	          title={error}
122	          isInline
123	          className="pf-v6-u-my-md"
124	        />
125	      )}
126	      <Label color="gold" className="pf-v6-u-my-lg">
127	        {getProviderLabel(providerType)}
128	      </Label>
129	      <LoginBody
130	        secretRef={secretRef}
131	        setSecretRef={setSecretRef}
132	        storageType={storageType}
133	        setStorageType={setStorageType}
134	      />
135	    </Modal>
136	  );
137	};
138	
139	export default LoginModal;

